using System.Text.Json.Serialization;
using Microsoft.AspNetCore.Http.HttpResults;
using ProductsApi.Models;
using ProductsApi.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<IProductService, InMemoryProductService>();
builder.Services.AddOpenApi();
builder.Services.ConfigureHttpJsonOptions(options =>
{
    options.SerializerOptions.Converters.Add(new JsonStringEnumConverter());
});

var app = builder.Build();

if (app.Environment.IsDevelopment())
{
    app.MapOpenApi();
}

app.UseHttpsRedirection();

var products = app.MapGroup("/api/products")
    .WithTags("Products");

products.MapGet("/", (IProductService service) =>
{
    return TypedResults.Ok(service.GetAll());
})
.WithName("GetAllProducts")
.WithSummary("List all products")
.WithDescription("Retrieves the complete list of products currently stored in the system.")
.Produces<IReadOnlyList<Product>>(StatusCodes.Status200OK);

products.MapGet("/{id:guid}", Results<Ok<Product>, NotFound> (Guid id, IProductService service) =>
{
    var product = service.GetById(id);
    return product is not null
        ? TypedResults.Ok(product)
        : TypedResults.NotFound();
})
.WithName("GetProductById")
.WithSummary("Get a product by ID")
.WithDescription("Retrieves a single product by its unique identifier. Returns 404 if the product does not exist.")
.Produces<Product>(StatusCodes.Status200OK)
.Produces(StatusCodes.Status404NotFound);

products.MapPost("/", Created<Product> (CreateProductRequest request, IProductService service) =>
{
    var product = service.Create(request);
    return TypedResults.Created($"/api/products/{product.Id}", product);
})
.WithName("CreateProduct")
.WithSummary("Create a new product")
.WithDescription("Creates a new product with the provided name, price, and category. A unique ID and timestamp are generated automatically.")
.Produces<Product>(StatusCodes.Status201Created);

app.Run();

